    recursiveNextTick();
  });
}

// 正确做法：使用 setImmediate 进行递归
function recursiveSetImmediate() {
  // setImmediate 在 check 阶段执行，不会阻塞其他阶段
  setImmediate(() => {
    console.log("不断执行 setImmediate...");
    recursiveSetImmediate();
  });
}

// 微任务优先级对比
setTimeout(() => console.log("A: timer"), 0);
setImmediate(() => console.log("B: check"));
process.nextTick(() => console.log("C: nextTick"));
