function fibonacci(n: number): number {
  if (n <= 1) return n;
  return fibonacci(n - 1) + fibonacci(n - 2);
}

// 接收主线程消息
parentPort.on("message", (data) => {
  const { taskId, n } = data;
  const result = fibonacci(n);
  // 发送结果回主线程
  parentPort.postMessage({ taskId, result });
